  position: fixed;
  top: 56px;
  right: 0;
  bottom: 50px;
  padding: 20px 16px;
  overflow-y: auto;
  background: #f0f0f0;
}
.stat-card, .trend-card, .gender-card {
  background: #fff;
  border-radius: 12px;
  padding: 18px;
  margin-bottom: 16px;
}
.stat-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 16px;
}
.stat-header h3 {
  font-size: 15px;
  font-weight: 600;
  color: #333;
}
.stat-refresh {
  width: 28px;
  height: 28px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  color: #999;
  font-size: 16px;
  border-radius: 50%;
  border: 1px solid #eee;
  background: #fff;
}
.stat-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 0;
}
.stat-row + .stat-row {
  border-top: 1px solid #f5f5f5;
}
.stat-label {
  font-size: 13px;
  color: #666;
}
.stat-value {
  font-size: 14px;
  font-weight: 600;
  color: #333;
}
.stat-value.red {
