}

/* Trend Chart */
.trend-header {
  margin-bottom: 16px;
}
.trend-header h3 {
  font-size: 15px;
  font-weight: 600;
  color: #333;
}
.trend-chart {
  width: 100%;
  height: 140px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #999;
  font-size: 13px;
}

/* Gender Chart */
.gender-header {
  margin-bottom: 16px;
}
.gender-header h3 {
  font-size: 15px;
  font-weight: 600;
  color: #333;
}
.pie-chart-container {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
}
.pie-chart {
  width: 130px;
  height: 130px;
  border-radius: 50%;
  background: conic-gradient(#ffb6c1 0% 60%, #b3d4fc 60% 100%);
  position: relative;
}
.pie-chart::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 0;
  height: 0;
}
.pie-legend {
  display: flex;
  gap: 16px;
  font-size: 12px;
  color: #666;
}
.legend-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  display: inline-block;
  margin-right: 4px;
  vertical-align: middle;
}
.legend-dot.pink { background: #ffb6c1; }
.legend-dot.blue { background: #b3d4fc; }

/* Footer */
.footer {
