<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>品类总览</title>
<style>
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
  background: #f5f7fa;
  color: #333;
  min-height: 100vh;
}

/* Header */
.header {
  background: #fff;
  height: 56px;
  display: flex;
  align-items: center;
  padding: 0 32px;
  box-shadow: 0 1px 4px rgba(0,0,0,0.08);
  position: sticky;
  top: 0;
  z-index: 100;
}

.logo {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-right: 40px;
}

.logo-icon {
  width: 28px;
  height: 28px;
  display: grid;
  grid-template-columns: 1fr 1fr;
  grid-template-rows: 1fr 1fr;
  gap: 2px;
}

.logo-icon span {
  background: #f08c2e;
  border-radius: 2px;
}

.logo-text {
  font-size: 18px;
  font-weight: 600;
  color: #333;
}

.nav-tabs {
  display: flex;
  align-items: center;
  gap: 0;
  margin-right: auto;
}

.nav-tab {
  padding: 8px 20px;
  font-size: 14px;
  color: #666;
  cursor: pointer;
  border-radius: 6px;
  transition: all 0.2s;
}

.nav-tab:hover {
  color: #333;
  background: #f5f5f5;
}

.nav-tab.active {
  background: #f08c2e;
  color: #fff;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 16px;
}

.search-box {
  display: flex;
  align-items: center;
  background: #f5f7fa;
  border: 1px solid #e8e8e8;
  border-radius: 8px;
  padding: 8px 14px;
  width: 240px;
}

.search-box svg {
  width: 16px;
  height: 16px;
  color: #999;
  margin-right: 8px;
  flex-shrink: 0;
}

.search-box input {
  border: none;
  background: transparent;
  outline: none;
  font-size: 14px;
  color: #333;
  width: 100%;
}

.search-box input::placeholder {
  color: #bbb;
}

.btn-add {
  display: flex;
  align-items: center;
  gap: 6px;
  background: #f08c2e;
  color: #fff;
  border: none;
  border-radius: 8px;
  padding: 10px 18px;
  font-size: 14px;
  cursor: pointer;
  white-space: nowrap;
}

.btn-add:hover {
  background: #e07d22;
}

/* Main Layout */
.main {
  display: flex;
  gap: 20px;
  padding: 24px 32px;
  max-width: 1400px;
  margin: 0 auto;
}

/* Left Sidebar */
.sidebar {
  width: 220px;
  flex-shrink: 0;
  background: #fff;
  border-radius: 12px;
  padding: 20px 0;
  height: fit-content;
  box-shadow: 0 1px 4px rgba(0,0,0,0.06);
}

.sidebar-title {
  font-size: 15px;
  font-weight: 600;
  padding: 0 20px 16px;
  color: #333;
}

.category-list {
  list-style: none;
}

.category-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 11px 20px;
  font-size: 14px;
  color: #555;
  cursor: pointer;
  transition: all 0.15s;
}

.category-item:hover {
  background: #f8f8f8;
}

.category-item.active {
  background: #e8f0fe;
  color: #2563eb;
  font-weight: 500;
}

.category-item .count {
  font-size: 13px;
  color: #999;
}

.category-item.active .count {
  color: #2563eb;
}

.category-item .arrow {
  font-size: 10px;
  color: #bbb;
}

.sidebar-footer {
