        <button class="float-btn float-btn-edit" title="编辑">✏</button>
        <button class="float-btn float-btn-help" title="帮助">?</button>
    </div>

    <script>
        // Slider interaction
        const slider = document.getElementById('strokeSlider');
        const sliderLabel = document.querySelector('.slider-label');

        slider.addEventListener('input', function() {
            sliderLabel.textContent = `笔画粗细 (${this.value}px)`;

            // Update slider background
            const value = (this.value - this.min) / (this.max - this.min) * 100;
            this.style.background = `linear-gradient(to right, #2d5a3d 0%, #2d5a3d ${value}%, #e0e0e0 ${value}%, #e0e0e0 100%)`;
        });

        // Initialize slider background
        slider.dispatchEvent(new Event('input'));

        // Button interactions
        document.querySelector('.btn-save').addEventListener('click', function() {
            alert('书写内容已保存！');
        });

        document.querySelector('.btn-clear').addEventListener('click', function() {
            if (confirm('确定要清空画布吗？')) {
                document.querySelector('.writing-textarea').value = '';
            }
        });

        // Add work button
        document.querySelector('.add-btn').addEventListener('click', function() {
            alert('添加作品功能');
        });

        // Work card buttons
        document.querySelectorAll('.work-btn.edit').forEach(btn => {
            btn.addEventListener('click', function() {
                alert('编辑作品功能');
            });
        });

        document.querySelectorAll('.work-btn.delete').forEach(btn => {
            btn.addEventListener('click', function() {
                if (confirm('确定要删除此作品吗？')) {
                    this.closest('.work-card').remove();
                }
            });
        });
    </script>
</body>
