    <title>宿舍生活记</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC", "Hiragino Sans GB", "Microsoft YaHei", sans-serif;
            background-color: #fff5f8;
            color: #333;
            min-height: 100vh;
        }

        /* Header */
        .header {
            background: linear-gradient(135deg, #ffb6c1 0%, #ffc0cb 50%, #ffd1dc 100%);
            height: 56px;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 24px;
            position: fixed;
            top: 0;
            left: 0;
            right: 0;
            z-index: 100;
        }

        .header-left {
            display: flex;
            align-items: center;
            gap: 8px;
        }

        .header-logo {
            font-size: 18px;
            color: #e91e63;
            display: flex;
            align-items: center;
            gap: 6px;
            font-weight: 600;
        }

        .header-nav {
            display: flex;
            gap: 40px;
            position: absolute;
            left: 50%;
            transform: translateX(-50%);
        }

        .header-nav a {
            text-decoration: none;
            color: #555;
            font-size: 15px;
            transition: color 0.2s;
        }

        .header-nav a:hover {
            color: #e91e63;
        }

        .header-right {
            display: flex;
            align-items: center;
            gap: 16px;
        }

        .bell-icon {
            font-size: 18px;
            color: #666;
            cursor: pointer;
        }

        .avatar {
            width: 36px;
            height: 36px;
            border-radius: 50%;
            background: linear-gradient(135deg, #ffd1dc 0%, #ffb6c1 100%);
            display: flex;
            align-items: center;
            justify-content: center;
            cursor: pointer;
        }

        .avatar::after {
            content: "👤";
            font-size: 16px;
        }

        .dropdown-arrow {
            font-size: 12px;
            color: #666;
            cursor: pointer;
        }

        /* Main Layout */
        .main-container {
            display: flex;
            padding-top: 56px;
            min-height: calc(100vh - 40px);
        }

        /* Left Sidebar */
        .sidebar-left {
            width: 190px;
            background: #fff;
            padding: 16px 12px;
            flex-shrink: 0;
            border-right: 1px solid #ffe4ec;
            min-height: calc(100vh - 56px - 40px);
        }

        .new-record-card {
            background: linear-gradient(135deg, #fff0f3 0%, #ffe8ef 100%);
            border-radius: 8px;
            padding: 16px;
            margin-bottom: 20px;
            cursor: pointer;
            border: 1px solid #ffe0ea;
        }

        .new-record-card:hover {
            background: linear-gradient(135deg, #ffe8ef 0%, #ffe0e8 100%);
        }

        .new-record-card .icon-row {
            display: flex;
            align-items: center;
            gap: 8px;
            margin-bottom: 6px;
        }

        .new-record-card .icon-row .plus-icon {
            width: 20px;
            height: 20px;
            background: #e91e63;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            color: #fff;
            font-size: 14px;
            font-weight: bold;
        }

        .new-record-card .icon-row span {
            font-weight: 600;
            color: #333;
            font-size: 14px;
        }

        .new-record-card .subtitle {
            color: #999;
            font-size: 12px;
            padding-left: 28px;
        }

        .sidebar-menu {
            margin-top: 8px;
        }

        .sidebar-menu-item {
            display: flex;
            align-items: flex-start;
            gap: 10px;
            padding: 14px 8px;
            cursor: pointer;
            border-radius: 6px;
            transition: background 0.2s;
        }

        .sidebar-menu-item:hover {
            background: #fff5f8;
        }

        .sidebar-menu-item .menu-icon {
            width: 24px;
            height: 24px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 12px;
            flex-shrink: 0;
            margin-top: 2px;
        }

        .sidebar-menu-item:nth-child(1) .menu-icon {
            background: #fff3e0;
            color: #ff9800;
        }

        .sidebar-menu-item:nth-child(2) .menu-icon {
            background: #e8f5e9;
            color: #4caf50;
        }

        .sidebar-menu-item:nth-child(3) .menu-icon {
            background: #e3f2fd;
            color: #2196f3;
        }

        .sidebar-menu-item .menu-content {
