            color: #333;
        }

        .sidebar-menu-item .menu-subtitle {
            font-size: 12px;
            color: #999;
        }

        .sidebar-tips {
            margin-top: 24px;
            padding-top: 16px;
            border-top: 1px solid #f0f0f0;
        }

        .sidebar-tips p {
            font-size: 11px;
            color: #999;
            line-height: 1.8;
        }

        /* Center Content */
        .content-center {
            flex: 1;
            padding: 24px 40px;
            max-width: 780px;
            margin: 0 auto;
        }

        .page-subtitle {
            text-align: center;
            color: #888;
            font-size: 14px;
            margin-bottom: 24px;
        }

        .add-record-btn {
            width: 100%;
            background: linear-gradient(135deg, #ffc0cb 0%, #ffb6c1 100%);
            border: none;
            border-radius: 8px;
            padding: 16px;
            font-size: 16px;
            color: #fff;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            gap: 8px;
            margin-bottom: 24px;
            font-weight: 500;
            transition: opacity 0.2s;
        }

        .add-record-btn:hover {
            opacity: 0.9;
        }

        .add-record-btn .plus {
            font-size: 20px;
            font-weight: bold;
        }

        /* Record Cards */
        .record-card {
            background: #fff;
            border-radius: 12px;
            padding: 24px;
            margin-bottom: 20px;
            box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);
            border: 1px solid #fff0f3;
        }

        .record-header {
            display: flex;
            align-items: flex-start;
            justify-content: space-between;
            margin-bottom: 16px;
        }

        .record-date-info {
            display: flex;
            align-items: flex-start;
            gap: 12px;
        }

        .record-date-icon {
            width: 32px;
            height: 32px;
            background: linear-gradient(135deg, #ffd1dc 0%, #ffb6c1 100%);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 14px;
            flex-shrink: 0;
        }

        .record-date-icon::after {
            content: "📝";
            font-size: 14px;
        }

        .record-date-text {
            display: flex;
            flex-direction: column;
        }

        .record-date {
            font-size: 16px;
            font-weight: 600;
            color: #333;
        }

        .record-time {
            font-size: 13px;
            color: #999;
        }

        .record-actions {
            display: flex;
            gap: 12px;
        }

        .record-actions button {
            background: none;
            border: none;
            cursor: pointer;
            font-size: 16px;
            color: #ccc;
            transition: color 0.2s;
        }

        .record-actions button:hover {
            color: #999;
        }

        .record-content {
            margin-bottom: 16px;
        }

        .record-content p {
            font-size: 14px;
            color: #444;
            line-height: 1.6;
            margin-bottom: 12px;
        }

        .record-images {
            display: flex;
            gap: 12px;
            flex-wrap: wrap;
        }

        .record-image {
            width: 120px;
            height: 90px;
            border-radius: 8px;
            object-fit: cover;
        }

        .record-image-placeholder {
            width: 120px;
            height: 90px;
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 12px;
            color: #fff;
        }

        .record-tag {
            display: inline-flex;
            align-items: center;
            gap: 6px;
            font-size: 13px;
            color: #888;
        }

        .record-tag .dot {
            width: 8px;
            height: 8px;
            border-radius: 50%;
            background: #ffc0cb;
        }

        /* Right Sidebar */
        .sidebar-right {
            width: 240px;
            padding: 24px 20px;
            flex-shrink: 0;
        }

        .sidebar-right-title {
            font-size: 18px;
            font-weight: 600;
            color: #333;
            margin-bottom: 16px;
        }

        .stat-card {
            background: linear-gradient(135deg, #fff5f8 0%, #ffe8ef 100%);
            border-radius: 12px;
            padding: 20px;
            margin-bottom: 24px;
            text-align: center;
            border: 1px solid #ffe0ea;
        }

        .stat-card .stat-label {
            font-size: 13px;
            color: #999;
            margin-bottom: 8px;
        }

        .stat-card .stat-value {
            font-size: 36px;
            font-weight: 700;
            color: #e91e63;
        }

        .mood-section {
            margin-bottom: 24px;
        }

        .mood-section-title {
            font-size: 15px;
            font-weight: 600;
            color: #333;
            margin-bottom: 12px;
        }

        .mood-bars {
            display: flex;
            gap: 6px;
            align-items: flex-end;
            height: 36px;
        }

        .mood-bar {
            width: 20px;
            background: #ffc0cb;
            border-radius: 4px 4px 0 0;
            transition: height 0.3s;
        }

        .tags-section {
            margin-bottom: 20px;
        }

        .tags-section-title {
            font-size: 15px;
            font-weight: 600;
            color: #333;
            margin-bottom: 12px;
        }

        .tag-list {
            display: flex;
            flex-direction: column;
            gap: 10px;
            align-items: flex-start;
        }

        .tag {
            padding: 6px 14px;
            border-radius: 20px;
            font-size: 13px;
            border: 1px solid;
        }

        .tag-开心 {
            background: #e8f5e9;
            color: #4caf50;
            border-color: #c8e6c9;
        }

        .tag-搞笑 {
            background: #fff3e0;
            color: #ff9800;
            border-color: #ffe0b2;
        }

        .tag-平淡 {
            background: #e3f2fd;
            color: #2196f3;
            border-color: #bbdefb;
        }

        .motivational-text {
            text-align: center;
            color: #999;
            font-size: 12px;
            margin-top: 20px;
            padding-top: 16px;
            border-top: 1px solid #f0f0f0;
        }

        /* Footer */
        .footer {
            height: 40px;
            background: #fff;
            border-top: 1px solid #ffe4ec;
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 24px;
            font-size: 12px;
            color: #999;
        }

        .footer-right {
            display: flex;
            gap: 20px;
        }

        .footer-right a {
            color: #999;
            text-decoration: none;
        }

        .footer-right a:hover {
            color: #e91e63;
        }

        /* SVG Icons */
        .icon-svg {
            display: inline-block;
        }
    </style>
